  1	import {
  2	  MenuToggle,
  3	  MenuToggleElement,
  4	  Select,
  5	  SelectList,
  6	  SelectOption,
  7	  TextInput,
  8	  ToolbarChip,
  9	  ToolbarChipGroup,
 10	  ToolbarFilter,
 11	  ToolbarGroup,
 12	} from '@patternfly/react-core';
 13	import { FilterIcon } from '@patternfly/react-icons';
 14	import React, { useEffect } from 'react';
 15	import { useTranslation } from 'react-i18next';
 16	import { useDebounce } from '../../hooks/useDebounce';
 17	import { TestIds } from '../../test-ids';
 18	import './attribute-filter.css';
 19	import { Attribute, AttributeList, Filters } from './filter.types';
 20	import { SearchSelect } from './search-select';
 21	
 22	interface AttributeFilterProps {
 23	  attributeList: AttributeList;
 24	  filters?: Filters;
 25	  onFiltersChange?: (filters: Filters) => void;
 26	  isDisabled?: boolean;
 27	  tenant?: string;
 28	}
 29	
 30	export const AttributeFilter: React.FC<AttributeFilterProps> = ({
 31	  attributeList,
 32	  filters = {},
 33	  onFiltersChange,
 34	  isDisabled,
 35	  tenant,
 36	}) => {
 37	  const { t } = useTranslation('plugin__logging-view-plugin');
 38	
 39	  const [isAttributeExpanded, setIsAttributeExpanded] = React.useState(false);
 40	  const changeFromInput = React.useRef(false);
 41	  const [textInputValue, setTextInputValue] = React.useState('');
 42	  const debouncedInputValue = useDebounce(textInputValue);
 43	  const [selectedAttributeId, setSelectedAttributeId] = React.useState<string | undefined>(
 44	    attributeList[0]?.id,
 45	  );
 46	  const selectRef = React.useRef<HTMLDivElement>(null);
 47	
 48	  const handleAttributeToggle = () => {
 49	    setIsAttributeExpanded(!isAttributeExpanded);
 50	  };
 51	
 52	  const textAttribute = attributeList.find(
 53	    (attr) => attr.id === selectedAttributeId && attr.valueType === 'text',
 54	  );
 55	
 56	  React.useEffect(() => {
 57	    if (textAttribute) {
 58	      const [initialText] = filters[textAttribute.id] ?? [];
 59	      changeFromInput.current = false;
 60	      setTextInputValue(initialText ?? '');
 61	    }
 62	  }, [textAttribute, filters]);
 63	
 64	  React.useEffect(() => {
 65	    // Audit tenant has only the content attribute
 66	    if (tenant === 'audit') {
 67	      setSelectedAttributeId(attributeList[0]?.id);
 68	    }
 69	  }, [tenant]);
 70	
 71	  useEffect(() => {
 72	    if (!selectedAttributeId) {
 73	      setSelectedAttributeId(attributeList[0]?.id);
 74	    }
 75	  }, [attributeList]);
 76	
 77	  const handleClickOutside = (event: MouseEvent) => {
 78	    if (isAttributeExpanded && !selectRef.current?.contains(event.target as Node)) {
 79	      setIsAttributeExpanded(false);
 80	    }
 81	  };
 82	
 83	  React.useEffect(() => {
 84	    if (isAttributeExpanded) {
 85	      window.addEventListener('click', handleClickOutside);
 86	    }
 87	    return () => {
 88	      window.removeEventListener('click', handleClickOutside);
 89	    };
 90	  }, [isAttributeExpanded]);
 91	
 92	  const handleAttributeSelect = (
 93	    _: React.MouseEvent<Element, MouseEvent> | undefined,
 94	    value: string | number | undefined,
 95	  ) => {
 96	    if (typeof value === 'string') {
 97	      setSelectedAttributeId(value);
 98	    }
 99	    setIsAttributeExpanded(false);
100	  };
101	
102	  const handleAttributeValueChange = (
103	    value: Set<string>,
104	    expandedSelections?: Map<string, Set<string>>,
105	  ) => {
106	    if (selectedAttributeId) {
107	      if (!filters[selectedAttributeId]) {
108	        filters[selectedAttributeId] = new Set();
109	      }
110	
111	      if (expandedSelections) {
112	        for (const [key, val] of expandedSelections) {
113	          filters[key] = val;
114	        }
115	
116	        onFiltersChange?.(filters);
117	      } else {
118	        onFiltersChange?.({
119	          ...filters,
120	          [selectedAttributeId]: value,
121	        });
122	      }
123	    }
124	  };
125	
126	  React.useEffect(() => {
127	    const [initialText] = textAttribute ? filters[textAttribute.id] ?? [] : [];
128	    const filterReset = initialText === undefined && debouncedInputValue === '';
129	
130	    if (!filterReset && changeFromInput.current) {
131	      handleAttributeValueChange(
132	        debouncedInputValue === '' ? new Set() : new Set([debouncedInputValue]),
133	      );
134	    }
135	  }, [debouncedInputValue]);
136	
137	  const handleDeleteAttributeGroup = (attribute: string) => () => {
138	    onFiltersChange?.({ ...filters, [attribute]: new Set() });
139	  };
140	
141	  const handleDeleteAttributeValue =
142	    (attribute: string) => (_category: string | ToolbarChipGroup, chip: string | ToolbarChip) => {
143	      filters?.[attribute]?.delete(chip as string);
144	      onFiltersChange?.({
145	        ...filters,
146	        [attribute]: new Set(filters[attribute]),
147	      });
148	    };
149	
150	  const handleInputValueChange = (value: string) => {
151	    changeFromInput.current = true;
152	    setTextInputValue(value);
153	  };
154	
155	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
156	    <MenuToggle
157	      ref={toggleRef}
158	      onClick={handleAttributeToggle}
159	      isExpanded={isAttributeExpanded}
160	      isDisabled={isDisabled}
161	      icon={<FilterIcon />}
162	      data-test={TestIds.AvailableAttributes}
163	      style={
164	        {
165	          width: '240px',
166	        } as React.CSSProperties
167	      }
168	    >
169	      {attributeList.find((attribute) => attribute.id === selectedAttributeId)?.name}
170	    </MenuToggle>
171	  );
172	
173	  const renderAttributeValueComponent = (attribute: Attribute) => {
174	    switch (attribute.valueType) {
175	      case 'text': {
176	        return (
177	          <TextInput
178	            key={`text-${attribute.id}`}
179	            placeholder={t('Search by {{attributeName}}', {
180	              attributeName: attribute.name,
181	            })}
182	            onChange={(_event, value: string) => handleInputValueChange(value)}
183	            className="lv-plugin__attribute-filter__text"
184	            aria-label={t('Search by {{attributeName}}', {
185	              attributeName: attribute.name,
186	            })}
187	            value={textInputValue}
188	          />
189	        );
190	      }
191	      case 'select':
192	        return (
193	          <SearchSelect
194	            key={`select-${attribute.id}`}
195	            attribute={attribute}
196	            onSelect={handleAttributeValueChange}
197	            filters={filters}
198	            tenant={tenant}
199	          />
200	        );
201	      case 'checkbox-select':
202	        return (
203	          <SearchSelect
204	            key={`checkbox-select-${attribute.id}`}
205	            attribute={attribute}
206	            onSelect={handleAttributeValueChange}
207	            filters={filters}
208	            isCheckbox={true}
209	            tenant={tenant}
210	          />
211	        );
212	    }
213	  };
214	
215	  return (
216	    <>
217	      <ToolbarGroup
218	        variant="filter-group"
219	        className="lv-plugin__attribute-filter"
220	        data-test={TestIds.AttributeFilters}
221	      >
222	        <div ref={selectRef}>
223	          <Select
224	            isOpen={isAttributeExpanded}
225	            onSelect={handleAttributeSelect}
226	            placeholder={t('Attribute')}
227	            toggle={toggle}
228	          >
229	            <SelectList>
230	              {attributeList.map(({ name: label, id }) => (
231	                <SelectOption key={id} value={id} isSelected={selectedAttributeId === id}>
232	                  {label}
233	                </SelectOption>
234	              ))}
235	            </SelectList>
236	          </Select>
237	        </div>
238	        {attributeList.map((attribute) => (
239	          <ToolbarFilter
240	            key={`toolbar-filter-${attribute.id}`}
241	            labels={Array.from(filters[attribute.id] ?? [])}
242	            deleteLabel={handleDeleteAttributeValue(attribute.id)}
243	            deleteLabelGroup={handleDeleteAttributeGroup(attribute.id)}
244	            categoryName={attribute.name}
245	          >
246	            {selectedAttributeId === attribute.id && renderAttributeValueComponent(attribute)}
247	          </ToolbarFilter>
248	        ))}
249	      </ToolbarGroup>
250	    </>
251	  );
252	};

