  1	import {
  2	  filtersFromQuery,
  3	  getContentPipelineStage,
  4	  getK8sMatcherFromSet,
  5	  getMatchersFromFilters,
  6	  getNamespaceMatcher,
  7	  getSeverityFilterPipelineStage,
  8	  queryFromFilters,
  9	} from '../attribute-filters';
 10	import { AttributeList, Filters } from '../components/filters/filter.types';
 11	import { LabelMatcher, PipelineStage } from '../logql-query';
 12	import { Schema } from '../logs.types';
 13	import { getStreamLabelsFromSchema, ResourceLabel } from '../parse-resources';
 14	
 15	const availableAttributes = (schema: Schema): AttributeList => {
 16	  const labelMatchers = getStreamLabelsFromSchema(schema);
 17	  const namespaceLabel = labelMatchers[ResourceLabel.Namespace];
 18	  const podLabel = labelMatchers[ResourceLabel.Pod];
 19	  const containerLabel = labelMatchers[ResourceLabel.Container];
 20	
 21	  return [
 22	    {
 23	      name: 'Content',
 24	      id: 'content',
 25	      valueType: 'text',
 26	    },
 27	    {
 28	      name: 'Namespaces',
 29	      label: namespaceLabel,
 30	      id: 'namespace',
 31	      options: () =>
 32	        Promise.resolve([
 33	          { option: 'Namespace 1', value: 'namespace-1' },
 34	          { option: 'Namespace 2', value: 'namespace-2' },
 35	        ]),
 36	      valueType: 'checkbox-select',
 37	    },
 38	    {
 39	      name: 'Pods',
 40	      label: podLabel,
 41	      id: 'pod',
 42	      options: () =>
 43	        Promise.resolve([
 44	          { option: 'Pod 1', value: 'pod-1' },
 45	          { option: 'Pod 2', value: 'pod-2' },
 46	        ]),
 47	      valueType: 'checkbox-select',
 48	    },
 49	    {
 50	      name: 'Containers',
 51	      label: containerLabel,
 52	      id: 'container',
 53	      options: () =>
 54	        Promise.resolve([
 55	          { option: 'Container 1', value: 'container-1' },
 56	          { value: 'container-2', option: 'Container 2' },
 57	        ]),
 58	      valueType: 'checkbox-select',
 59	    },
 60	  ];
 61	};
 62	
 63	describe('Attribute filters', () => {
 64	  it('should return matchers from filters', () => {
 65	    [
 66	      {
 67	        filters: {},
 68	        expected: [],
 69	      },
 70	      {
 71	        filters: {
 72	          namespace: new Set(['my-namespace', 'other-namespace']),
 73	        },
 74	        expected: [
 75	          {
 76	            label: 'kubernetes_namespace_name',
 77	            operator: '=~',
 78	            value: '"my-namespace|other-namespace"',
 79	          },
 80	        ],
 81	      },
 82	      {
 83	        filters: {
 84	          namespace: new Set(['my-namespace', 'other-namespace']),
 85	          pod: new Set(['pod-1', 'pod-2']),
 86	          container: new Set(['container-1', 'container-2']),
 87	        },
 88	        expected: [
 89	          {
 90	            label: 'kubernetes_namespace_name',
 91	            operator: '=~',
 92	            value: '"my-namespace|other-namespace"',
 93	          },
 94	          {
 95	            label: 'kubernetes_pod_name',
 96	            operator: '=~',
 97	            value: '"pod-1|pod-2"',
 98	          },
 99	          {
100	            label: 'kubernetes_container_name',
101	            operator: '=~',
102	            value: '"container-1|container-2"',
103	          },
104	        ],
105	      },
106	      {
107	        filters: {
108	          namespace: new Set(['my-namespace', 'other-namespace']),
109	          pod: new Set(['pod-1', 'pod-2']),
110	          container: new Set(['container-1', 'container-2']),
111	        },
112	        schema: Schema.otel,
113	        expected: [
114	          {
115	            label: 'k8s_namespace_name',
116	            operator: '=~',
117	            value: '"my-namespace|other-namespace"',
118	          },
119	          {
120	            label: 'k8s_pod_name',
121	            operator: '=~',
122	            value: '"pod-1|pod-2"',
123	          },
124	          {
125	            label: 'k8s_container_name',
126	            operator: '=~',
127	            value: '"container-1|container-2"',
128	          },
129	        ],
130	      },
131	    ].forEach(
132	      ({
133	        filters,
134	        expected,
135	        schema,
136	      }: {
137	        filters: Filters;
138	        expected: LabelMatcher[];
139	        schema?: Schema;
140	      }) => {
141	        const matchers = getMatchersFromFilters({ filters, schema: schema ?? Schema.viaq });
142	        expect(matchers).toEqual(expected);
143	      },
144	    );
145	  });
146	
147	  it('should get content pipeline stage from filters', () => {
148	    [
149	      {
150	        filters: {},
151	        expected: undefined,
152	      },
153	      {
154	        filters: {
155	          content: new Set(['my search query']),
156	        },
157	        expected: { operator: '|=', value: '`my search query`' },
158	      },
159	    ].forEach(({ filters, expected }) => {
160	      const pipeline = getContentPipelineStage(filters);
161	      expect(pipeline).toEqual(expected);
162	    });
163	  });
164	
165	  test('getSelectorFromSet', () => {
166	    [
167	      {
168	        label: 'test',
169	        set: new Set<string>(),
170	        expected: undefined,
171	      },
172	      {
173	        label: 'test',
174	        set: new Set<string>(['']),
175	        expected: { label: 'test', operator: '=', value: '""' },
176	      },
177	      {
178	        label: 'test',
179	        set: new Set(['value']),
180	        expected: { label: 'test', operator: '=', value: '"value"' },
181	      },
182	      {
183	        label: 'test',
184	        set: new Set(['value-1', 'value-2']),
185	        expected: { label: 'test', operator: '=~', value: '"value-1|value-2"' },
186	      },
187	    ].forEach(({ set, label, expected }) => {
188	      const selectors = getK8sMatcherFromSet(label, set);
189	      expect(selectors).toEqual(expected);
190	    });
191	  });
192	
193	  test('getNamespaceStreamSelector', () => {
194	    [
195	      {
196	        namespace: 'my-namespace',
197	        expected: {
198	          label: 'kubernetes_namespace_name',
199	          operator: '=',
200	          value: '"my-namespace"',
201	        },
202	      },
203	      {
204	        namespace: '',
205	        expected: {
206	          label: 'kubernetes_namespace_name',
207	          operator: '=',
208	          value: '""',
209	        },
210	      },
211	      {
212	        namespace: 'otel-namespace',
213	        schema: Schema.otel,
214	        expected: {
215	          label: 'k8s_namespace_name',
216	          operator: '=',
217	          value: '"otel-namespace"',
218	        },
219	      },
220	      {
221	        namespace: undefined,
222	        expected: undefined,
223	      },
224	    ].forEach(
225	      ({
226	        namespace,
227	        expected,
228	        schema,
229	      }: {
230	        namespace: string | undefined;
