  1	import {
  2	  MenuToggle,
  3	  MenuToggleElement,
  4	  Select,
  5	  SelectList,
  6	  SelectOption,
  7	  SelectOptionProps,
  8	  TextInput,
  9	  ToolbarFilter,
 10	  ToolbarGroup,
 11	  ToolbarLabel,
 12	  ToolbarLabelGroup,
 13	} from '@patternfly/react-core';
 14	import { FilterIcon } from '@patternfly/react-icons';
 15	import React, { useEffect } from 'react';
 16	import { useTranslation } from 'react-i18next';
 17	import { useDebounce } from '../../hooks/useDebounce';
 18	import { TestIds } from '../../test-ids';
 19	import './attribute-filter.css';
 20	import { Attribute, AttributeList, Filters } from './filter.types';
 21	import { SearchSelect } from './search-select';
 22	
 23	interface AttributeFilterProps {
 24	  attributeList: AttributeList;
 25	  filters?: Filters;
 26	  onFiltersChange?: (filters: Filters) => void;
 27	  isDisabled?: boolean;
 28	  tenant?: string;
 29	}
 30	
 31	export const AttributeFilter: React.FC<AttributeFilterProps> = ({
 32	  attributeList,
 33	  filters = {},
 34	  onFiltersChange,
 35	  isDisabled,
 36	  tenant,
 37	}) => {
 38	  const { t } = useTranslation('plugin__logging-view-plugin');
 39	
 40	  const [isAttributeExpanded, setIsAttributeExpanded] = React.useState(false);
 41	  const changeFromInput = React.useRef(false);
 42	  const [textInputValue, setTextInputValue] = React.useState('');
 43	  const debouncedInputValue = useDebounce(textInputValue);
 44	  const [selectedAttributeId, setSelectedAttributeId] = React.useState<string | undefined>(
 45	    attributeList[0]?.id,
 46	  );
 47	  const selectRef = React.useRef<HTMLDivElement>(null);
 48	
 49	  const handleAttributeToggle = () => {
 50	    setIsAttributeExpanded(!isAttributeExpanded);
 51	  };
 52	
 53	  const textAttribute = attributeList.find(
 54	    (attr) => attr.id === selectedAttributeId && attr.valueType === 'text',
 55	  );
 56	
 57	  React.useEffect(() => {
 58	    if (textAttribute) {
 59	      const [initialText] = filters[textAttribute.id] ?? [];
 60	      changeFromInput.current = false;
 61	      setTextInputValue(initialText ?? '');
 62	    }
 63	  }, [textAttribute, filters]);
 64	
 65	  React.useEffect(() => {
 66	    // Audit tenant has only the content attribute
 67	    if (tenant === 'audit') {
 68	      setSelectedAttributeId(attributeList[0]?.id);
 69	    }
 70	  }, [tenant]);
 71	
 72	  useEffect(() => {
 73	    if (!selectedAttributeId) {
 74	      setSelectedAttributeId(attributeList[0]?.id);
 75	    }
 76	  }, [attributeList]);
 77	
 78	  const handleClickOutside = (event: MouseEvent) => {
 79	    if (isAttributeExpanded && !selectRef.current?.contains(event.target as Node)) {
 80	      setIsAttributeExpanded(false);
 81	    }
 82	  };
 83	
 84	  React.useEffect(() => {
 85	    if (isAttributeExpanded) {
 86	      window.addEventListener('click', handleClickOutside);
 87	    }
 88	    return () => {
 89	      window.removeEventListener('click', handleClickOutside);
 90	    };
 91	  }, [isAttributeExpanded]);
 92	
 93	  const handleAttributeSelect = (
 94	    _: React.MouseEvent<Element, MouseEvent> | undefined,
 95	    value: SelectOptionProps['value'] | undefined,
 96	  ) => {
 97	    if (typeof value === 'string') {
 98	      setSelectedAttributeId(value);
 99	    }
100	    setIsAttributeExpanded(false);
101	  };
102	
103	  const handleAttributeValueChange = (
104	    value: Set<string>,
105	    expandedSelections?: Map<string, Set<string>>,
106	  ) => {
107	    if (selectedAttributeId) {
108	      if (!filters[selectedAttributeId]) {
109	        filters[selectedAttributeId] = new Set();
110	      }
111	
112	      if (expandedSelections) {
113	        for (const [key, val] of expandedSelections) {
114	          filters[key] = val;
115	        }
116	
117	        onFiltersChange?.(filters);
118	      } else {
119	        onFiltersChange?.({
120	          ...filters,
121	          [selectedAttributeId]: value,
122	        });
123	      }
124	    }
125	  };
126	
127	  React.useEffect(() => {
128	    const [initialText] = textAttribute ? filters[textAttribute.id] ?? [] : [];
129	    const filterReset = initialText === undefined && debouncedInputValue === '';
130	
131	    if (!filterReset && changeFromInput.current) {
132	      handleAttributeValueChange(
133	        debouncedInputValue === '' ? new Set() : new Set([debouncedInputValue]),
134	      );
135	    }
136	  }, [debouncedInputValue]);
137	
138	  const handleDeleteAttributeGroup = (attribute: string) => () => {
139	    onFiltersChange?.({ ...filters, [attribute]: new Set() });
140	  };
141	
142	  const handleDeleteAttributeValue =
143	    (attribute: string) => (_category: string | ToolbarLabelGroup, chip: string | ToolbarLabel) => {
144	      filters?.[attribute]?.delete(chip as string);
145	      onFiltersChange?.({
146	        ...filters,
147	        [attribute]: new Set(filters[attribute]),
148	      });
149	    };
150	
151	  const handleInputValueChange = (value: string) => {
152	    changeFromInput.current = true;
153	    setTextInputValue(value);
154	  };
155	
156	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
157	    <MenuToggle
158	      ref={toggleRef}
159	      onClick={handleAttributeToggle}
160	      isExpanded={isAttributeExpanded}
161	      isDisabled={isDisabled}
162	      icon={<FilterIcon />}
163	      data-test={TestIds.AvailableAttributes}
164	      style={
165	        {
166	          width: '240px',
167	        } as React.CSSProperties
168	      }
169	    >
170	      {attributeList.find((attribute) => attribute.id === selectedAttributeId)?.name}
171	    </MenuToggle>
172	  );
173	
174	  const renderAttributeValueComponent = (attribute: Attribute) => {
175	    switch (attribute.valueType) {
176	      case 'text': {
177	        return (
178	          <TextInput
179	            key={`text-${attribute.id}`}
180	            placeholder={t('Search by {{attributeName}}', {
181	              attributeName: attribute.name,
182	            })}
183	            onChange={(_event, value: string) => handleInputValueChange(value)}
184	            className="lv-plugin__attribute-filter__text"
185	            aria-label={t('Search by {{attributeName}}', {
186	              attributeName: attribute.name,
187	            })}
188	            value={textInputValue}
189	          />
190	        );
191	      }
192	      case 'select':
193	        return (
194	          <SearchSelect
195	            key={`select-${attribute.id}`}
196	            attribute={attribute}
197	            onSelect={handleAttributeValueChange}
198	            filters={filters}
199	            tenant={tenant}
200	          />
201	        );
202	      case 'checkbox-select':
203	        return (
204	          <SearchSelect
205	            key={`checkbox-select-${attribute.id}`}
206	            attribute={attribute}
207	            onSelect={handleAttributeValueChange}
208	            filters={filters}
209	            isCheckbox={true}
210	            tenant={tenant}
211	          />
212	        );
213	    }
214	  };
215	
216	  return (
217	    <>
218	      <ToolbarGroup
219	        variant="filter-group"
220	        className="lv-plugin__attribute-filter"
221	        data-test={TestIds.AttributeFilters}
222	      >
223	        <div ref={selectRef}>
224	          <Select
225	            isOpen={isAttributeExpanded}
226	            onSelect={handleAttributeSelect}
227	            toggle={toggle}
228	          >
229	            <SelectList>
230	              {attributeList.map(({ name: label, id }) => (
231	                <SelectOption key={id} value={id} isSelected={selectedAttributeId === id}>
232	                  {label}
233	                </SelectOption>
234	              ))}
235	            </SelectList>
236	          </Select>
237	        </div>
238	        {attributeList.map((attribute) => (
239	          <ToolbarFilter
240	            key={`toolbar-filter-${attribute.id}`}
241	            labels={Array.from(filters[attribute.id] ?? [])}
242	            deleteLabel={handleDeleteAttributeValue(attribute.id)}
243	            deleteLabelGroup={handleDeleteAttributeGroup(attribute.id)}
244	            categoryName={attribute.name}
245	          >
246	            {selectedAttributeId === attribute.id && renderAttributeValueComponent(attribute)}
247	          </ToolbarFilter>
248	        ))}
249	      </ToolbarGroup>
250	    </>
251	  );
252	};

